class Solution {
public:
    Solution(vector<int>& w) {
        prefix_sum.push_back(w[0]);
        for (int i = 1; i < w.size(); ++i) {
            prefix_sum.push_back(prefix_sum.back() + w[i]);
        }
        total_sum = prefix_sum.back();
    }

    int pickIndex() {
        int target = rand() % total_sum + 1;
        int left = 0, right = prefix_sum.size() - 1;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (prefix_sum[mid] < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
private:
    vector<int> prefix_sum;
    int total_sum;
};

